def write_text_file(path: Path, content: str) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")


def copy_self(target_root: Path) -> None:
    self_path = Path(__file__).resolve()
    if self_path.exists():
        write_text_file(target_root / "create_project.py", self_path.read_text(encoding="utf-8"))


def create_repository(target_root: Path, force: bool = False) -> Path:
    target_root = target_root.resolve()
    if target_root.exists() and any(target_root.iterdir()) and not force:
        raise SystemExit(
            f"Target directory '{target_root}' already exists and is not empty. "
            "Use --force to overwrite files in place or choose a new output path."
        )
    target_root.mkdir(parents=True, exist_ok=True)

    for rel_path, content in FILES.items():
        write_text_file(target_root / rel_path, content)

    copy_self(target_root)
    return target_root


def create_zip_archive(source_root: Path, zip_path: Path | None = None) -> Path:
    source_root = source_root.resolve()
    if zip_path is None:
        zip_path = source_root.with_suffix('.zip')
    else:
        zip_path = zip_path.resolve()

    if zip_path.exists():
        zip_path.unlink()

    with zipfile.ZipFile(zip_path, 'w', compression=zipfile.ZIP_DEFLATED, compresslevel=9) as archive:
        for file_path in sorted(source_root.rglob('*')):
            if file_path.is_dir():
                continue
            archive.write(file_path, arcname=file_path.relative_to(source_root.parent))
    return zip_path


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Create the municipal workflow repository on disk.")
    parser.add_argument(
        '--output',
        default=DEFAULT_PROJECT_NAME,
        help='Target directory for the generated repository. Defaults to %(default)s.',
    )
    parser.add_argument(
        '--force',
        action='store_true',
        help='Allow writing into an existing non-empty directory.',
    )
    parser.add_argument(
        '--zip',
        action='store_true',
        help='Also create a ZIP archive next to the generated repository.',
    )
    parser.add_argument(
        '--zip-path',
        default='',
        help='Optional explicit ZIP archive path. Only used with --zip.',
    )
    return parser.parse_args()


def main() -> None:
    args = parse_args()
    output_dir = Path(args.output)
    repo_root = create_repository(output_dir, force=args.force)
    print(f"Repository created at: {repo_root}")

    if args.zip:
        zip_path = Path(args.zip_path) if args.zip_path else None
        archive_path = create_zip_archive(repo_root, zip_path)
        print(f"ZIP archive created at: {archive_path}")


if __name__ == '__main__':
    main()
